BEGIN;

DROP TABLE IF EXISTS public.pacientes_importacion_sismo_26jun26;

CREATE TABLE public.pacientes_importacion_sismo_26jun26 (
  id BIGSERIAL PRIMARY KEY,
  import_id INTEGER NOT NULL,
  nombre_completo VARCHAR(50) NOT NULL,
  cedula_tipo VARCHAR(1) NULL,
  cedula VARCHAR(9) NULL,
  telefono_contacto VARCHAR(15) NULL,
  edad INTEGER NULL CHECK (edad IS NULL OR (edad >= 0 AND edad <= 120)),
  estado VARCHAR(100) NULL,
  municipio VARCHAR(100) NULL,
  parroquia VARCHAR(100) NULL,
  foto_paciente TEXT NULL,
  ubicacion_especifica TEXT NULL,
  estado_salud VARCHAR(100) NULL,
  direccion_referencial TEXT NULL,
  observaciones TEXT NULL,
  hospital TEXT NULL,
  fuentes TEXT NULL,
  warnings TEXT NULL,
  source_rows TEXT NULL,
  nombres_alternativos TEXT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_pacientes_26jun26_nombre ON public.pacientes_importacion_sismo_26jun26 (nombre_completo);
CREATE INDEX idx_pacientes_26jun26_cedula ON public.pacientes_importacion_sismo_26jun26 (cedula);
CREATE INDEX idx_pacientes_26jun26_ubicacion ON public.pacientes_importacion_sismo_26jun26 (ubicacion_especifica);
